import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.isVisible

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        intent?.let {
            handleIncomingIntent(it)
        }
    }

    private fun handleIncomingIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    intent.getStringExtra(Intent.EXTRA_TEXT)?.let {
                        processSharedUrl(it)
                    }
                }

                if (intent.type?.startsWith("image/") == true) {
                    (intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))?.let {
                        processSharedImage(it)
                    }
                }
            }
        }
    }

    private fun processSharedUrl(url: String) {
        // Process the URL here
        Toast.makeText(this, "Processed URL: $url", Toast.LENGTH_LONG).show()
    }

    private fun processSharedImage(uri: Uri) {
        // Process the image URI here
        Toast.makeText(this, "Processed Image URI: $uri", Toast.LENGTH_LONG).show()
    }
}